import type { QueryClient } from "@tanstack/react-query";
import type * as AppServer from "app-server-types";

import {
  MCP_SERVERS_QUERY_KEY,
  MCP_SERVERS_STATUS_QUERY_KEY,
  type ConfigWriteTarget,
} from "@/queries/config-queries";
import type { RecommendedMcpServer } from "@/types/mcp";

export function isHttpRecommendedMcpServerConfigValue(
  value: AppServer.v2.ConfigEdit["value"],
): boolean {
  return (
    value != null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    "url" in value
  );
}

export async function installRecommendedMcpServerConfig({
  server,
  configWriteTarget,
  writeConfig,
  queryClient,
}: {
  server: RecommendedMcpServer;
  configWriteTarget: ConfigWriteTarget | null;
  writeConfig: (params: {
    filePath: string | null;
    expectedVersion: string | null;
    edits: Array<AppServer.v2.ConfigEdit>;
  }) => Promise<unknown>;
  queryClient: QueryClient;
}): Promise<{ didInstall: boolean; isHttpServerConfigValue: boolean }> {
  const isHttpServerConfigValue = isHttpRecommendedMcpServerConfigValue(
    server.config.value,
  );
  if (!configWriteTarget) {
    return { didInstall: false, isHttpServerConfigValue };
  }

  await writeConfig({
    edits: [
      {
        keyPath: server.config.keyPath,
        value: server.config.value,
        mergeStrategy: "upsert",
      },
    ],
    filePath: configWriteTarget.filePath,
    expectedVersion: configWriteTarget.expectedVersion,
  });

  const invalidations = [
    queryClient.invalidateQueries({
      queryKey: MCP_SERVERS_QUERY_KEY,
    }),
  ];
  if (isHttpServerConfigValue) {
    invalidations.push(
      queryClient.invalidateQueries({
        queryKey: MCP_SERVERS_STATUS_QUERY_KEY,
      }),
    );
  }
  await Promise.all(invalidations);

  return { didInstall: true, isHttpServerConfigValue };
}
