export function getRecommendedMcpServerById(
  serverId: RecommendedMcpServer["id"],
): RecommendedMcpServer {
  const server = RECOMMENDED_MCP_SERVERS.find(
    (recommendedServer) => recommendedServer.id === serverId,
  );
  if (!server) {
    throw new Error(`Missing recommended MCP server: ${serverId}`);
  }
  return server;
}

